option.value:
@import "tailwindcss";
@source "../application/**/*.{ts,tsx}";
@source "../bundles/**/*.{ts,tsx}";
@source "../components/**/*.{ts,tsx}";
@plugin "@tailwindcss/typography";

@theme {
    /* Colors */
    --color-background: var(--bg-app);
    --color-foreground: var(--text-main);

    --color-card: var(--bg-surface);
    --color-card-foreground: var(--text-main);

    --color-popover: var(--bg-surface);
    --color-popover-foreground: var(--text-main);

    --color-primary: var(--primary);
    --color-primary-foreground: var(--text-inverted);

    --color-secondary: var(--secondary);
    --color-secondary-foreground: var(--text-main);

    --color-muted: var(--text-muted);
    --color-muted-foreground: var(--text-main);

    --color-accent: var(--accent);
    --color-accent-foreground: var(--text-inverted);

    --color-destructive: var(--color-error);
    --color-destructive-foreground: var(--text-inverted);

    --color-border: var(--border-primary);
    --color-input: var(--border-primary);
    --color-ring: var(--primary);

    /* Border Radii */
    --radius-lg: var(--border-radius-large);
    --radius-md: var(--border-radius-base);
    --radius-sm: var(--btn-radius);
    /* Map standard radius to border-radius-large for shadcn base alignment */
    --radius: var(--border-radius-large);

    /* Ring Widths */
    --ring-width-3: 3px;

    /* Animations & Keyframes */
    --animate-marquee: marquee 25s linear infinite reverse;

    @keyframes marquee {
        0% {
            transform: translateX(0);
        }

        100% {
            transform: translateX(-50%);
        }
    }
}

:root:not(.theme-dark) {
    --bg-app: var(--ui-app-bg);
    --bg-surface: var(--ui-surface-strong);
    --text-main: var(--ui-text);
    --text-muted: var(--ui-text-muted);
    --text-inverted: #ffffff;
    --border-primary: var(--ui-border);
    --border-radius-large: 1rem;
    --border-radius-base: 0.75rem;
    --btn-radius: 0.65rem;
    --font-family-sans: Inter;
    --ui-app-bg: #f6f8fc;
    --ui-app-glow: rgba(91, 124, 250, 0.12);
    --ui-app-glow-alt: rgba(99, 102, 241, 0.08);
    --ui-surface: rgba(255, 255, 255, 0.84);
    --ui-surface-strong: #ffffff;
    --ui-surface-muted: #eef3ff;
    --ui-border: rgba(91, 124, 250, 0.18);
    --ui-border-strong: rgba(91, 124, 250, 0.28);
    --ui-text: #1f2937;
    --ui-text-muted: #5b6475;
    --ui-accent: #5b7cfa;
    --ui-accent-2: #7c5cff;
    --ui-accent-hover: #4868e6;
    --ui-accent-soft: rgba(91, 124, 250, 0.12);
    --ui-accent-soft-strong: rgba(91, 124, 250, 0.18);
    --ui-surface-gradient-start: rgba(255, 255, 255, 0.96);
    --ui-surface-gradient-end: rgba(240, 245, 255, 0.94);
    --ui-shadow-popup: 0 16px 36px rgba(59, 84, 150, 0.14);
    --ui-shadow-dialog: 0 24px 64px rgba(59, 84, 150, 0.18);
    --ui-overlay: rgba(15, 23, 42, 0.12);
}

.theme-dark {
    --bg-app: var(--ui-app-bg);
    --bg-surface: var(--ui-surface-strong);
    --text-main: var(--ui-text);
    --text-muted: var(--ui-text-muted);
    --text-inverted: #ffffff;
    --border-primary: var(--ui-border);
    --border-radius-large: 1rem;
    --border-radius-base: 0.75rem;
    --btn-radius: 0.65rem;
    --font-family-sans: Inter;
    --ui-app-bg: #12151d;
    --ui-app-glow: rgba(110, 168, 255, 0.12);
    --ui-app-glow-alt: rgba(59, 130, 246, 0.08);
    --ui-surface: rgba(24, 29, 40, 0.9);
    --ui-surface-strong: #1b2230;
    --ui-surface-muted: #151a24;
    --ui-border: rgba(110, 168, 255, 0.16);
    --ui-border-strong: rgba(110, 168, 255, 0.28);
    --ui-text: #e8ebf2;
    --ui-text-muted: #aab2c2;
    --ui-accent: #74a7ff;
    --ui-accent-2: #7ee0c3;
    --ui-accent-hover: #4f8dff;
    --ui-accent-soft: rgba(116, 167, 255, 0.14);
    --ui-accent-soft-strong: rgba(116, 167, 255, 0.2);
    --ui-surface-gradient-start: rgba(28, 35, 49, 0.98);
    --ui-surface-gradient-end: rgba(23, 28, 40, 0.96);
    --ui-shadow-popup: 0 16px 36px rgba(0, 0, 0, 0.35);
    --ui-shadow-dialog: 0 24px 70px rgba(0, 0, 0, 0.45);
    --ui-overlay: rgba(0, 0, 0, 0.42);
    background-color: var(--ui-app-bg) !important;
    color: var(--ui-text) !important;
}

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
    background:
        radial-gradient(circle at top left, var(--ui-app-glow) 0, transparent 28%),
        radial-gradient(circle at top right, color-mix(in srgb, var(--ui-accent-soft) 85%, transparent) 0, transparent 26%),
        radial-gradient(circle at bottom left, color-mix(in srgb, var(--ui-accent-soft-strong) 70%, transparent) 0, transparent 24%),
        radial-gradient(circle at bottom right, var(--ui-app-glow-alt) 0, transparent 30%),
        var(--ui-app-bg);
    color: var(--ui-text);
    font-family: var(--font-family-sans), system-ui, sans-serif;
}

/* Base text color overrides for elements that don't have explicit tailwind color classes */
.theme-dark:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark :not(.storefront-canvas):not(.storefront-canvas *):not(button):not(input):not(select):not(textarea):not(svg) {
    color: #e3e3e3;
}

/* Background overrides */
.theme-dark .bg-white:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-50:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-50\/50:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-gray-100\/40:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-100\/40:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark aside:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark header:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: #2c2c2c !important;
}

/* Sub-panels, inputs, and list containers (theme uses a darker color for inner boxes) */
.theme-dark .bg-gray-100:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-100:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark input:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark select:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark textarea:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark button.w-full:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-dashed:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-\[\#f4f5f7\]:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: #1e1e1e !important;
    color: #ffffff !important;
}

/* Border overrides */
.theme-dark .border:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-200:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-100:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-300:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-gray-200:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-b:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-t:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-l:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-r:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-100\/85:not(.storefront-canvas):not(.storefront-canvas *) {
    border-color: #3e3e3e !important;
}

/* Text color overrides */
.theme-dark .text-zinc-950:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-900:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-800:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-700:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-600:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-gray-900:not(.storefront-canvas):not(.storefront-canvas *) {
    color: #e3e3e3 !important;
}

.theme-dark .text-zinc-500:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-400:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-gray-500:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-gray-400:not(.storefront-canvas):not(.storefront-canvas *) {
    color: #b3b3b3 !important;
}

.theme-dark .text-zinc-300:not(.storefront-canvas):not(.storefront-canvas *) {
    color: #8c8c8c !important;
}

/* theme accents */
.theme-dark .text-blue-500:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-blue-600:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:text-blue-600:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark [data-state=active]:not(.storefront-canvas):not(.storefront-canvas *) {
    color: #0c8ce9 !important;
}

.theme-dark [data-state=active]:not(.storefront-canvas):not(.storefront-canvas *) {
    border-color: #0c8ce9 !important;
}

/* Custom indicator for Radix Tabs active state */
.theme-dark button[data-state=active]:not(.storefront-canvas):not(.storefront-canvas *) {
    border-bottom-color: #0c8ce9 !important;
    color: #ffffff !important;
}

/* Hover background overrides */
.theme-dark .hover\:bg-zinc-50:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-zinc-100:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-gray-50:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-gray-100:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-zinc-100\/60:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-zinc-200:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-gray-200:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-red-50:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-red-50\/50:hover:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: #3c3c3c !important;
}

/* Hover text overrides */
.theme-dark .hover\:text-zinc-700:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:text-zinc-600:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:text-zinc-950:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .group:hover .text-zinc-800:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .group:hover .text-zinc-750:not(.storefront-canvas):not(.storefront-canvas *) {
    color: #ffffff !important;
}

/* Scroll area background */
.theme-dark [data-radix-scroll-area-viewport]:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark [style*="overflow: scroll"]:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark [style*="overflow: auto"]:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: #2c2c2c !important;
}

/* Dropdown menu and Radix select content portals globally in the editor page */
div[data-radix-popper-content-wrapper] > div,
div[data-radix-popper-content-wrapper] [role="menu"],
div[data-radix-popper-content-wrapper] [role="listbox"] {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
    box-shadow: var(--ui-shadow-popup) !important;
    backdrop-filter: blur(12px) saturate(1.1);
}

div[data-radix-popper-content-wrapper] [role="menuitem"],
div[data-radix-popper-content-wrapper] [role="option"],
div[data-radix-popper-content-wrapper] [data-highlighted] {
    background-color: transparent !important;
    color: var(--ui-text) !important;
}

div[data-radix-popper-content-wrapper] [role="menuitem"]:hover,
div[data-radix-popper-content-wrapper] [role="option"]:hover,
div[data-radix-popper-content-wrapper] [data-highlighted]:hover,
div[data-radix-popper-content-wrapper] [data-highlighted][role="menuitem"],
div[data-radix-popper-content-wrapper] [data-highlighted][role="option"] {
    background: linear-gradient(90deg, var(--ui-accent-soft), color-mix(in srgb, var(--ui-accent-soft-strong) 72%, transparent)) !important;
    color: var(--ui-text) !important;
}

div[data-radix-popper-content-wrapper] svg {
    color: var(--ui-text-muted) !important;
}

/* Light and dark dialog styling for Radix portals */
div[data-radix-focus-guard] ~ div[style*="position: fixed"],
div[role="dialog"] {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
    box-shadow: var(--ui-shadow-dialog) !important;
}

div[role="dialog"] div[class*="bg-white"],
div[role="dialog"] div[class*="bg-zinc-50"],
div[role="dialog"] div[class*="bg-zinc-100"],
div[role="dialog"] div[class*="bg-gray-100"],
div[role="dialog"] div[class*="bg-[#0c0d12]"],
div[role="dialog"] div[class*="bg-[#11131a]"],
div[role="dialog"] div[class*="bg-zinc-50\/50"] {
    background-color: var(--ui-surface-strong) !important;
    color: var(--ui-text) !important;
}

div[role="dialog"] input,
div[role="dialog"] select,
div[role="dialog"] textarea,
div[role="dialog"] [class*="TabsList"],
div[role="dialog"] [role="tablist"] {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border-color: var(--ui-border) !important;
}

div[role="dialog"] button {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
}

div[role="dialog"] button:hover {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
}

div[role="dialog"] button[type="submit"] {
    background: linear-gradient(135deg, var(--ui-accent), var(--ui-accent-2)) !important;
    border-color: var(--ui-accent) !important;
    color: #ffffff !important;
}

div[role="dialog"] button[type="submit"]:hover {
    background-color: var(--ui-accent-hover) !important;
    border-color: var(--ui-accent-hover) !important;
}

div[role="dialog"] button[role="tab"],
div[role="dialog"] [role="tablist"] button {
    background-color: transparent !important;
    border: none !important;
    color: var(--ui-text-muted) !important;
    box-shadow: none !important;
}

div[role="dialog"] button[role="tab"][data-state="active"],
div[role="dialog"] [role="tablist"] button[data-state="active"],
div[role="dialog"] [role="tablist"] button[class*="bg-white"] {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
    box-shadow: 0 1px 4px rgba(91, 124, 250, 0.12) !important;
    border: 1px solid var(--ui-border-strong) !important;
}

div[role="dialog"] button[role="tab"]:hover,
div[role="dialog"] [role="tablist"] button:hover {
    color: var(--ui-text) !important;
    background-color: var(--ui-accent-soft) !important;
}

div[role="dialog"] [class*="Title"],
div[role="dialog"] [class*="Close"] {
    color: var(--ui-text) !important;
}

div[role="dialog"] [class*="text-zinc-900"],
div[role="dialog"] [class*="text-zinc-800"] {
    color: var(--ui-text) !important;
}

div[role="dialog"] [class*="text-zinc-400"],
div[role="dialog"] [class*="text-zinc-500"] {
    color: var(--ui-text-muted) !important;
}

div[role="dialog"] [class*="border"] {
    border-color: var(--ui-border) !important;
}

/* Premium blurred backdrop overlay */
div[class*="Overlay"],
div[class*="overlay"],
div[style*="backdrop-filter"] {
    background-color: var(--ui-overlay) !important;
    backdrop-filter: blur(4px) !important;
}

/* Dialog & Radix Modal Portals in Dark Mode */
.theme-dark div[data-radix-focus-guard] ~ div[style*="position: fixed"],
.theme-dark div[role="dialog"] {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
    box-shadow: var(--ui-shadow-dialog) !important;
}

/* Override inner panels (bg-white, bg-zinc, bg-gray) inside dialogs */
.theme-dark div[role="dialog"] div[class*="bg-white"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-50"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-100"],
.theme-dark div[role="dialog"] div[class*="bg-gray-100"],
.theme-dark div[role="dialog"] div[class*="bg-[#0c0d12]"],
.theme-dark div[role="dialog"] div[class*="bg-[#11131a]"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-50\/50"] {
    background-color: var(--ui-surface-strong) !important;
    color: var(--ui-text) !important;
}

/* Darken inner input areas, textareas, and tabs list inside dialogs */
.theme-dark div[role="dialog"] input,
.theme-dark div[role="dialog"] select,
.theme-dark div[role="dialog"] textarea,
.theme-dark div[role="dialog"] [class*="TabsList"],
.theme-dark div[role="dialog"] [role="tablist"] {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border-color: var(--ui-border) !important;
}

/* Preserve JSON / Code highlights inside dialog code viewers */
.theme-dark div[role="dialog"] textarea.font-mono {
    background-color: var(--ui-surface-muted) !important;
    color: #89ddff !important;
    border-color: var(--ui-border) !important;
}
.theme-dark div[role="dialog"] pre.font-mono {
    background-color: var(--ui-surface-muted) !important;
    color: #c3e88d !important;
    border-color: var(--ui-border) !important;
}
.theme-dark div[role="dialog"] div[class*="bg-[#0c0d12]"] {
    background-color: var(--ui-surface-muted) !important;
}
.theme-dark div[role="dialog"] div[class*="bg-[#11131a]"] {
    background-color: var(--ui-surface) !important;
}

/* Dialog button styling */
.theme-dark div[role="dialog"] button {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
}

.theme-dark div[role="dialog"] button:hover {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
}

/* Tabs list container in dark mode */
.theme-dark div[role="dialog"] [role="tablist"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-100"] {
    background-color: var(--ui-surface) !important;
    border: 1px solid var(--ui-border) !important;
    padding: 2px !important;
}

/* Inactive tabs inside dialogs */
.theme-dark div[role="dialog"] button[role="tab"],
.theme-dark div[role="dialog"] [role="tablist"] button {
    background-color: transparent !important;
    border: none !important;
    color: var(--ui-text-muted) !important;
    box-shadow: none !important;
}

/* Active tabs inside dialogs */
.theme-dark div[role="dialog"] button[role="tab"][data-state="active"],
.theme-dark div[role="dialog"] [role="tablist"] button[data-state="active"],
.theme-dark div[role="dialog"] [role="tablist"] button[class*="bg-white"] {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
    box-shadow: 0 1px 4px rgba(91, 124, 250, 0.12) !important;
    border: 1px solid var(--ui-border-strong) !important;
}

/* Tab hover states */
.theme-dark div[role="dialog"] button[role="tab"]:hover,
.theme-dark div[role="dialog"] [role="tablist"] button:hover {
    color: var(--ui-text) !important;
    background-color: var(--ui-accent-soft) !important;
}

.theme-dark div[role="dialog"] button[type="submit"] {
    background: linear-gradient(135deg, var(--ui-accent), var(--ui-accent-2)) !important;
    border-color: var(--ui-accent) !important;
    color: #ffffff !important;
}

.theme-dark div[role="dialog"] button[type="submit"]:hover {
    background-color: var(--ui-accent-hover) !important;
}

/* Dialog title and close icon color overrides */
.theme-dark div[role="dialog"] [class*="Title"],
.theme-dark div[role="dialog"] [class*="Close"] {
    color: var(--ui-text) !important;
}

.theme-dark div[role="dialog"] [class*="text-zinc-900"],
.theme-dark div[role="dialog"] [class*="text-zinc-800"] {
    color: var(--ui-text) !important;
}

.theme-dark div[role="dialog"] [class*="text-zinc-400"],
.theme-dark div[role="dialog"] [class*="text-zinc-500"] {
    color: var(--ui-text-muted) !important;
}

/* Border overrides inside dialog */
.theme-dark div[role="dialog"] [class*="border"] {
    border-color: var(--ui-border) !important;
}

/* Premium blurred backdrop overlay */
.theme-dark div[class*="Overlay"],
.theme-dark div[class*="overlay"],
.theme-dark div[style*="backdrop-filter"] {
    background-color: var(--ui-overlay) !important;
    backdrop-filter: blur(4px) !important;
}

/* Custom Sidebar Context Menu */
.editor-context-menu {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end));
    border: 1px solid var(--ui-border) !important;
    color: var(--ui-text) !important;
    box-shadow: var(--ui-shadow-popup);
}
.theme-dark .editor-context-menu {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    border-color: var(--ui-border) !important;
    color: var(--ui-text) !important;
    box-shadow: var(--ui-shadow-popup) !important;
}

.editor-context-menu-item {
    display: flex;
    align-items: center;
    gap: 8px;
    width: 100%;
    padding: 6px 10px;
    text-align: left;
    cursor: pointer;
    transition: background-color 100ms;
}
.editor-context-menu-item:hover {
    background: linear-gradient(90deg, var(--ui-accent-soft), color-mix(in srgb, var(--ui-accent-soft-strong) 72%, transparent));
    color: var(--ui-text);
}
.theme-dark .editor-context-menu-item:hover {
    background: linear-gradient(90deg, var(--ui-accent-soft), color-mix(in srgb, var(--ui-accent-soft-strong) 72%, transparent)) !important;
    color: var(--ui-text) !important;
}

@import "tailwindcss";
@source "../application/**/*.{ts,tsx}";
@source "../bundles/**/*.{ts,tsx}";
@source "../components/**/*.{ts,tsx}";
@plugin "@tailwindcss/typography";

@theme {
    /* Colors */
    --color-background: var(--bg-app);
    --color-foreground: var(--text-main);

    --color-card: var(--bg-surface);
    --color-card-foreground: var(--text-main);

    --color-popover: var(--bg-surface);
    --color-popover-foreground: var(--text-main);

    --color-primary: var(--primary);
    --color-primary-foreground: var(--text-inverted);

    --color-secondary: var(--secondary);
    --color-secondary-foreground: var(--text-main);

    --color-muted: var(--text-muted);
    --color-muted-foreground: var(--text-main);

    --color-accent: var(--accent);
    --color-accent-foreground: var(--text-inverted);

    --color-destructive: var(--color-error);
    --color-destructive-foreground: var(--text-inverted);

    --color-border: var(--border-primary);
    --color-input: var(--border-primary);
    --color-ring: var(--primary);

    /* Border Radii */
    --radius-lg: var(--border-radius-large);
    --radius-md: var(--border-radius-base);
    --radius-sm: var(--btn-radius);
    /* Map standard radius to border-radius-large for shadcn base alignment */
    --radius: var(--border-radius-large);

    /* Ring Widths */
    --ring-width-3: 3px;

    /* Animations & Keyframes */
    --animate-marquee: marquee 25s linear infinite reverse;

    @keyframes marquee {
        0% {
            transform: translateX(0);
        }

        100% {
            transform: translateX(-50%);
        }
    }
}

:root:not(.theme-dark) {
    --bg-app: var(--ui-app-bg);
    --bg-surface: var(--ui-surface-strong);
    --text-main: var(--ui-text);
    --text-muted: var(--ui-text-muted);
    --text-inverted: #ffffff;
    --border-primary: var(--ui-border);
    --border-radius-large: 1rem;
    --border-radius-base: 0.75rem;
    --btn-radius: 0.65rem;
    --font-family-sans: Inter;
    --ui-app-bg: #f7f9fd;
    --ui-app-glow: rgba(91, 124, 250, 0.08);
    --ui-app-glow-alt: rgba(124, 92, 255, 0.05);
    --ui-surface: rgba(255, 255, 255, 0.9);
    --ui-surface-strong: #ffffff;
    --ui-surface-muted: #f3f6ff;
    --ui-border: rgba(91, 124, 250, 0.14);
    --ui-border-strong: rgba(91, 124, 250, 0.22);
    --ui-text: #1f2937;
    --ui-text-muted: #677085;
    --ui-accent: #5b7cfa;
    --ui-accent-2: #7c5cff;
    --ui-accent-hover: #4868e6;
    --ui-accent-soft: rgba(91, 124, 250, 0.1);
    --ui-accent-soft-strong: rgba(91, 124, 250, 0.14);
    --ui-surface-gradient-start: rgba(255, 255, 255, 0.96);
    --ui-surface-gradient-end: rgba(244, 247, 255, 0.96);
    --ui-shadow-popup: 0 14px 32px rgba(59, 84, 150, 0.12);
    --ui-shadow-dialog: 0 22px 56px rgba(59, 84, 150, 0.15);
    --ui-overlay: rgba(15, 23, 42, 0.12);
}

.theme-dark {
    --bg-app: var(--ui-app-bg);
    --bg-surface: var(--ui-surface-strong);
    --text-main: var(--ui-text);
    --text-muted: var(--ui-text-muted);
    --text-inverted: #ffffff;
    --border-primary: var(--ui-border);
    --border-radius-large: 1rem;
    --border-radius-base: 0.75rem;
    --btn-radius: 0.65rem;
    --font-family-sans: Inter;
    --ui-app-bg: #11141b;
    --ui-app-glow: rgba(116, 167, 255, 0.09);
    --ui-app-glow-alt: rgba(126, 224, 195, 0.04);
    --ui-surface: rgba(25, 30, 41, 0.92);
    --ui-surface-strong: #1a2030;
    --ui-surface-muted: #141924;
    --ui-border: rgba(116, 167, 255, 0.12);
    --ui-border-strong: rgba(116, 167, 255, 0.2);
    --ui-text: #edf1f7;
    --ui-text-muted: #a5afbf;
    --ui-accent: #7aa9ff;
    --ui-accent-2: #68d6be;
    --ui-accent-hover: #5d98ff;
    --ui-accent-soft: rgba(122, 169, 255, 0.12);
    --ui-accent-soft-strong: rgba(122, 169, 255, 0.16);
    --ui-surface-gradient-start: rgba(28, 34, 47, 0.98);
    --ui-surface-gradient-end: rgba(21, 26, 37, 0.97);
    --ui-shadow-popup: 0 14px 32px rgba(0, 0, 0, 0.3);
    --ui-shadow-dialog: 0 22px 60px rgba(0, 0, 0, 0.4);
    --ui-overlay: rgba(0, 0, 0, 0.42);
    background-color: var(--ui-app-bg) !important;
    color: var(--ui-text) !important;
}

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
    background:
        radial-gradient(circle at top left, var(--ui-app-glow) 0, transparent 28%),
        radial-gradient(circle at top right, color-mix(in srgb, var(--ui-accent-soft) 85%, transparent) 0, transparent 26%),
        radial-gradient(circle at bottom left, color-mix(in srgb, var(--ui-accent-soft-strong) 70%, transparent) 0, transparent 24%),
        radial-gradient(circle at bottom right, var(--ui-app-glow-alt) 0, transparent 30%),
        var(--ui-app-bg);
    color: var(--ui-text);
    font-family: var(--font-family-sans), system-ui, sans-serif;
}

html {
    scrollbar-color: var(--ui-border) transparent;
    scrollbar-width: thin;
}

::selection {
    background: var(--ui-accent-soft-strong);
    color: var(--ui-text);
}

.theme-dark ::selection {
    background: rgba(122, 169, 255, 0.22);
    color: #ffffff;
}

:focus-visible {
    outline: 2px solid var(--ui-accent);
    outline-offset: 2px;
    box-shadow: 0 0 0 4px var(--ui-accent-soft);
}

button,
input,
select,
textarea,
a,
[role="button"],
[role="tab"] {
    transition: background-color 140ms ease, border-color 140ms ease, color 140ms ease, box-shadow 140ms ease, opacity 140ms ease;
}

::-webkit-scrollbar {
    width: 10px;
    height: 10px;
}

::-webkit-scrollbar-track {
    background: transparent;
}

::-webkit-scrollbar-thumb {
    background: var(--ui-border);
    border-radius: 999px;
    border: 3px solid transparent;
    background-clip: content-box;
}

@media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
        scroll-behavior: auto !important;
    }

    .animate-marquee {
        animation: none !important;
    }
}

/* Base text color overrides for elements that don't have explicit tailwind color classes */
.theme-dark:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark :not(.storefront-canvas):not(.storefront-canvas *):not(button):not(input):not(select):not(textarea):not(svg) {
    color: #e3e3e3;
}

/* Background overrides */
.theme-dark .bg-white:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-50:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-50\/50:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-gray-100\/40:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-100\/40:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark aside:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark header:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: var(--ui-surface-strong) !important;
}

/* Sub-panels, inputs, and list containers (theme uses a darker color for inner boxes) */
.theme-dark .bg-gray-100:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-zinc-100:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark input:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark select:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark textarea:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark button.w-full:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-dashed:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .bg-\[\#f4f5f7\]:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
}

/* Border overrides */
.theme-dark .border:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-200:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-100:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-300:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-gray-200:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-b:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-t:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-l:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-r:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .border-zinc-100\/85:not(.storefront-canvas):not(.storefront-canvas *) {
    border-color: var(--ui-border-strong) !important;
}

/* Text color overrides */
.theme-dark .text-zinc-950:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-900:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-800:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-700:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-600:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-gray-900:not(.storefront-canvas):not(.storefront-canvas *) {
    color: var(--ui-text) !important;
}

.theme-dark .text-zinc-500:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-zinc-400:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-gray-500:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-gray-400:not(.storefront-canvas):not(.storefront-canvas *) {
    color: var(--ui-text-muted) !important;
}

.theme-dark .text-zinc-300:not(.storefront-canvas):not(.storefront-canvas *) {
    color: #8e96a7 !important;
}

/* theme accents */
.theme-dark .text-blue-500:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .text-blue-600:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:text-blue-600:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark [data-state=active]:not(.storefront-canvas):not(.storefront-canvas *) {
    color: var(--ui-accent) !important;
}

.theme-dark [data-state=active]:not(.storefront-canvas):not(.storefront-canvas *) {
    border-color: var(--ui-accent) !important;
}

/* Custom indicator for Radix Tabs active state */
.theme-dark button[data-state=active]:not(.storefront-canvas):not(.storefront-canvas *) {
    border-bottom-color: var(--ui-accent) !important;
    color: var(--ui-text) !important;
}

/* Hover background overrides */
.theme-dark .hover\:bg-zinc-50:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-zinc-100:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-gray-50:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-gray-100:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-zinc-100\/60:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-zinc-200:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-gray-200:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-red-50:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:bg-red-50\/50:hover:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: var(--ui-accent-soft) !important;
}

/* Hover text overrides */
.theme-dark .hover\:text-zinc-700:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:text-zinc-600:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .hover\:text-zinc-950:hover:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .group:hover .text-zinc-800:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark .group:hover .text-zinc-750:not(.storefront-canvas):not(.storefront-canvas *) {
    color: var(--ui-text) !important;
}

/* Scroll area background */
.theme-dark [data-radix-scroll-area-viewport]:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark [style*="overflow: scroll"]:not(.storefront-canvas):not(.storefront-canvas *),
.theme-dark [style*="overflow: auto"]:not(.storefront-canvas):not(.storefront-canvas *) {
    background-color: var(--ui-surface-strong) !important;
}

/* Dropdown menu and Radix select content portals globally in the editor page */
div[data-radix-popper-content-wrapper] > div,
div[data-radix-popper-content-wrapper] [role="menu"],
div[data-radix-popper-content-wrapper] [role="listbox"] {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
    box-shadow: var(--ui-shadow-popup) !important;
    backdrop-filter: blur(12px) saturate(1.1);
}

div[data-radix-popper-content-wrapper] [role="menuitem"],
div[data-radix-popper-content-wrapper] [role="option"],
div[data-radix-popper-content-wrapper] [data-highlighted] {
    background-color: transparent !important;
    color: var(--ui-text) !important;
}

div[data-radix-popper-content-wrapper] [role="menuitem"]:hover,
div[data-radix-popper-content-wrapper] [role="option"]:hover,
div[data-radix-popper-content-wrapper] [data-highlighted]:hover,
div[data-radix-popper-content-wrapper] [data-highlighted][role="menuitem"],
div[data-radix-popper-content-wrapper] [data-highlighted][role="option"] {
    background: linear-gradient(90deg, var(--ui-accent-soft), color-mix(in srgb, var(--ui-accent-soft-strong) 72%, transparent)) !important;
    color: var(--ui-text) !important;
}

div[data-radix-popper-content-wrapper] svg {
    color: var(--ui-text-muted) !important;
}

/* Light and dark dialog styling for Radix portals */
div[data-radix-focus-guard] ~ div[style*="position: fixed"],
div[role="dialog"] {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
    box-shadow: var(--ui-shadow-dialog) !important;
}

div[role="dialog"] div[class*="bg-white"],
div[role="dialog"] div[class*="bg-zinc-50"],
div[role="dialog"] div[class*="bg-zinc-100"],
div[role="dialog"] div[class*="bg-gray-100"],
div[role="dialog"] div[class*="bg-[#0c0d12]"],
div[role="dialog"] div[class*="bg-[#11131a]"],
div[role="dialog"] div[class*="bg-zinc-50\/50"] {
    background-color: var(--ui-surface-strong) !important;
    color: var(--ui-text) !important;
}

div[role="dialog"] input,
div[role="dialog"] select,
div[role="dialog"] textarea,
div[role="dialog"] [class*="TabsList"],
div[role="dialog"] [role="tablist"] {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border-color: var(--ui-border) !important;
}

div[role="dialog"] button {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
}

div[role="dialog"] button:hover {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
}

div[role="dialog"] button[type="submit"] {
    background: linear-gradient(135deg, var(--ui-accent), var(--ui-accent-2)) !important;
    border-color: var(--ui-accent) !important;
    color: #ffffff !important;
}

div[role="dialog"] button[type="submit"]:hover {
    background-color: var(--ui-accent-hover) !important;
    border-color: var(--ui-accent-hover) !important;
}

div[role="dialog"] button[role="tab"],
div[role="dialog"] [role="tablist"] button {
    background-color: transparent !important;
    border: none !important;
    color: var(--ui-text-muted) !important;
    box-shadow: none !important;
}

div[role="dialog"] button[role="tab"][data-state="active"],
div[role="dialog"] [role="tablist"] button[data-state="active"],
div[role="dialog"] [role="tablist"] button[class*="bg-white"] {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
    box-shadow: 0 1px 4px rgba(91, 124, 250, 0.12) !important;
    border: 1px solid var(--ui-border-strong) !important;
}

div[role="dialog"] button[role="tab"]:hover,
div[role="dialog"] [role="tablist"] button:hover {
    color: var(--ui-text) !important;
    background-color: var(--ui-accent-soft) !important;
}

div[role="dialog"] [class*="Title"],
div[role="dialog"] [class*="Close"] {
    color: var(--ui-text) !important;
}

div[role="dialog"] [class*="text-zinc-900"],
div[role="dialog"] [class*="text-zinc-800"] {
    color: var(--ui-text) !important;
}

div[role="dialog"] [class*="text-zinc-400"],
div[role="dialog"] [class*="text-zinc-500"] {
    color: var(--ui-text-muted) !important;
}

div[role="dialog"] [class*="border"] {
    border-color: var(--ui-border) !important;
}

/* Premium blurred backdrop overlay */
div[class*="Overlay"],
div[class*="overlay"],
div[style*="backdrop-filter"] {
    background-color: var(--ui-overlay) !important;
    backdrop-filter: blur(4px) !important;
}

/* Dialog & Radix Modal Portals in Dark Mode */
.theme-dark div[data-radix-focus-guard] ~ div[style*="position: fixed"],
.theme-dark div[role="dialog"] {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
    box-shadow: var(--ui-shadow-dialog) !important;
}

/* Override inner panels (bg-white, bg-zinc, bg-gray) inside dialogs */
.theme-dark div[role="dialog"] div[class*="bg-white"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-50"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-100"],
.theme-dark div[role="dialog"] div[class*="bg-gray-100"],
.theme-dark div[role="dialog"] div[class*="bg-[#0c0d12]"],
.theme-dark div[role="dialog"] div[class*="bg-[#11131a]"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-50\/50"] {
    background-color: var(--ui-surface-strong) !important;
    color: var(--ui-text) !important;
}

/* Darken inner input areas, textareas, and tabs list inside dialogs */
.theme-dark div[role="dialog"] input,
.theme-dark div[role="dialog"] select,
.theme-dark div[role="dialog"] textarea,
.theme-dark div[role="dialog"] [class*="TabsList"],
.theme-dark div[role="dialog"] [role="tablist"] {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border-color: var(--ui-border) !important;
}

/* Preserve JSON / Code highlights inside dialog code viewers */
.theme-dark div[role="dialog"] textarea.font-mono {
    background-color: var(--ui-surface-muted) !important;
    color: #89ddff !important;
    border-color: var(--ui-border) !important;
}
.theme-dark div[role="dialog"] pre.font-mono {
    background-color: var(--ui-surface-muted) !important;
    color: #c3e88d !important;
    border-color: var(--ui-border) !important;
}
.theme-dark div[role="dialog"] div[class*="bg-[#0c0d12]"] {
    background-color: var(--ui-surface-muted) !important;
}
.theme-dark div[role="dialog"] div[class*="bg-[#11131a]"] {
    background-color: var(--ui-surface) !important;
}

/* Dialog button styling */
.theme-dark div[role="dialog"] button {
    background-color: var(--ui-surface) !important;
    color: var(--ui-text) !important;
    border: 1px solid var(--ui-border) !important;
}

.theme-dark div[role="dialog"] button:hover {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
}

/* Tabs list container in dark mode */
.theme-dark div[role="dialog"] [role="tablist"],
.theme-dark div[role="dialog"] div[class*="bg-zinc-100"] {
    background-color: var(--ui-surface) !important;
    border: 1px solid var(--ui-border) !important;
    padding: 2px !important;
}

/* Inactive tabs inside dialogs */
.theme-dark div[role="dialog"] button[role="tab"],
.theme-dark div[role="dialog"] [role="tablist"] button {
    background-color: transparent !important;
    border: none !important;
    color: var(--ui-text-muted) !important;
    box-shadow: none !important;
}

/* Active tabs inside dialogs */
.theme-dark div[role="dialog"] button[role="tab"][data-state="active"],
.theme-dark div[role="dialog"] [role="tablist"] button[data-state="active"],
.theme-dark div[role="dialog"] [role="tablist"] button[class*="bg-white"] {
    background-color: var(--ui-accent-soft) !important;
    color: var(--ui-text) !important;
    box-shadow: 0 1px 4px rgba(91, 124, 250, 0.12) !important;
    border: 1px solid var(--ui-border-strong) !important;
}

/* Tab hover states */
.theme-dark div[role="dialog"] button[role="tab"]:hover,
.theme-dark div[role="dialog"] [role="tablist"] button:hover {
    color: var(--ui-text) !important;
    background-color: var(--ui-accent-soft) !important;
}

.theme-dark div[role="dialog"] button[type="submit"] {
    background: linear-gradient(135deg, var(--ui-accent), var(--ui-accent-2)) !important;
    border-color: var(--ui-accent) !important;
    color: #ffffff !important;
}

.theme-dark div[role="dialog"] button[type="submit"]:hover {
    background-color: var(--ui-accent-hover) !important;
}

/* Dialog title and close icon color overrides */
.theme-dark div[role="dialog"] [class*="Title"],
.theme-dark div[role="dialog"] [class*="Close"] {
    color: var(--ui-text) !important;
}

.theme-dark div[role="dialog"] [class*="text-zinc-900"],
.theme-dark div[role="dialog"] [class*="text-zinc-800"] {
    color: var(--ui-text) !important;
}

.theme-dark div[role="dialog"] [class*="text-zinc-400"],
.theme-dark div[role="dialog"] [class*="text-zinc-500"] {
    color: var(--ui-text-muted) !important;
}

/* Border overrides inside dialog */
.theme-dark div[role="dialog"] [class*="border"] {
    border-color: var(--ui-border) !important;
}

/* Premium blurred backdrop overlay */
.theme-dark div[class*="Overlay"],
.theme-dark div[class*="overlay"],
.theme-dark div[style*="backdrop-filter"] {
    background-color: var(--ui-overlay) !important;
    backdrop-filter: blur(4px) !important;
}

/* Custom Sidebar Context Menu */
.editor-context-menu {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end));
    border: 1px solid var(--ui-border) !important;
    color: var(--ui-text) !important;
    box-shadow: var(--ui-shadow-popup);
}
.theme-dark .editor-context-menu {
    background-color: var(--ui-surface-strong) !important;
    background-image: linear-gradient(180deg, var(--ui-surface-gradient-start), var(--ui-surface-gradient-end)) !important;
    border-color: var(--ui-border) !important;
    color: var(--ui-text) !important;
    box-shadow: var(--ui-shadow-popup) !important;
}

.editor-context-menu-item {
    display: flex;
    align-items: center;
    gap: 8px;
    width: 100%;
    padding: 6px 10px;
    text-align: left;
    cursor: pointer;
    transition: background-color 100ms;
}
.editor-context-menu-item:hover {
    background: linear-gradient(90deg, var(--ui-accent-soft), color-mix(in srgb, var(--ui-accent-soft-strong) 72%, transparent));
    color: var(--ui-text);
}
.theme-dark .editor-context-menu-item:hover {
    background: linear-gradient(90deg, var(--ui-accent-soft), color-mix(in srgb, var(--ui-accent-soft-strong) 72%, transparent)) !important;
    color: var(--ui-text) !important;
}
